public void toString(MethodWriter mw, StringBuilder buf, int indent) {
    mw.ident(buf, indent);
    buf.append("if (");
    condition.toString(mw, buf, indent);
    buf.append(") {").append('\n');

    for (int i = 0; i < statements.size(); i++) {
        if (i != 0) {
            buf.append('\n');
        }
        Statement stmt = statements.get(i);
        stmt.toString(mw, buf, indent + 1);
    }

    buf.append('\n');
    mw.ident(buf, indent);
    buf.append("}");

    if (elseStmt != null) {
        buf.append(" else {\n");
        for (int i = 0; i < elseStmt.statements.size(); i++) {
            if (i != 0) {
                buf.append('\n');
            }
            Statement stmt = elseStmt.statements.get(i);
            stmt.toString(mw, buf, indent + 1);
        }
        buf.append('\n');
        mw.ident(buf, indent);
        buf.append("}");
    }
}

public void toString(MethodWriter mw, StringBuilder buf, int indent) {
    buf.append("new ").append(type).append('[');

    if (size != null) {
        size.toString(mw, buf, indent);
    }
    buf.append(']');
    if (values != null) {
        int length = values.length;
        if (length > 0) {
            buf.append('{');

            buf.append('\n');
            mw.ident(buf, indent + 2);

            for (int i = 0; i < length; i++) {
                if (i != 0) {
                    buf.append(",\n");
                    mw.ident(buf, indent + 2);
                }
                values[i].toString(mw, buf, indent + 2);
            }

            buf.append('\n');
            mw.ident(buf, indent);
            buf.append('}');
        } else if (length == 0) {
            buf.append("{}");
        }
    }
}

static String boxed(String type) {
    String boxed = type;
    switch (type) {
        case "int":
            boxed = "Integer";
            break;
        case "long":
            boxed = "Long";
            break;
        case "float":
            boxed = "Float";
            break;
        case "double":
            boxed = "Double";
            break;
        case "boolean":
            boxed = "Boolean";
            break;
        case "char":
            boxed = "Character";
            break;
        case "byte":
            boxed = "Byte";
            break;
        case "short":
            boxed = "Short";
            break;
        default:
    }
    return boxed;
}

private ListBuffer<JCTree.JCStatement> genWriteBigDecimal(
        MethodWriterContext mwc,
        AttributeInfo attributeInfo,
        int i
) {
    ListBuffer<JCTree.JCStatement> stmts = new ListBuffer<>();

    String type = attributeInfo.type.toString();
    JCTree.JCVariableDecl fieldValue = defVar("bigDecimal" + i, qualIdent(type), genWriteFieldValue(attributeInfo, mwc.object, mwc.beanType));
    stmts.append(fieldValue);

    stmts.append(
            defIf(
                    or(notNull(fieldValue), isEnable(mwc.contextFeatures, WriteNulls)),
                    block(
                            genWriteFieldName(mwc, attributeInfo, i),
                            exec(mwc.jsonWriterMethod("writeDecimal", fieldValue))
                    )
            )
    );
    return stmts;
}

public DateTimeFormatter getDateFormatter(Locale locale) {
    if (format == null || formatMillis || formatISO8601 || formatUnixTime) {
        return null;
    }

    if (dateFormatter != null) {
        if ((this.locale == null && (locale == null || locale == Locale.getDefault()))
                || this.locale != null && this.locale.equals(locale)
        ) {
            return dateFormatter;
        }
    }

    if (locale == null) {
        if (this.locale == null) {
            return dateFormatter = DateTimeFormatter.ofPattern(format);
        } else {
            return dateFormatter = DateTimeFormatter.ofPattern(format, this.locale);
        }
    }

    return dateFormatter = DateTimeFormatter.ofPattern(format, locale);
}

public void visitLdcInsn(final String value) {
    final int CONSTANT_STRING_TAG = 8;

    lastBytecodeOffset = code.length;
    // Add the instruction to the bytecode of the method.
    Symbol constantSymbol = symbolTable.addConstantUtf8Reference(CONSTANT_STRING_TAG, value);
    int constantIndex = constantSymbol.index;
    if (constantIndex >= 256) {
        code.put12(Constants.LDC_W, constantIndex);
    } else {
        code.put11(Opcodes.LDC, constantIndex);
    }
    // If needed, update the maximum stack size and number of locals, and stack map frames.
    if (currentBasicBlock != null) {
        currentBasicBlock.frame.execute(Opcodes.LDC, 0, constantSymbol, symbolTable);
    }
}

private void visitSwitchInsn(final Label dflt, final Label[] labels) {
    if (currentBasicBlock != null) {
        currentBasicBlock.frame.execute(Opcodes.LOOKUPSWITCH, 0, null, null);
        // Add all the labels as successors of the current basic block.
        addSuccessorToCurrentBasicBlock(dflt);
        dflt.getCanonicalInstance().flags |= Label.FLAG_JUMP_TARGET;
        for (int i = 0; i < labels.length; i++) {
            Label label = labels[i];
            addSuccessorToCurrentBasicBlock(label);
            label.getCanonicalInstance().flags |= Label.FLAG_JUMP_TARGET;
        }
        // End the current basic block.
        endCurrentBasicBlockWithNoSuccessor();
    }
}

private Symbol put(final Symbol entry) {
    if (entryCount > (entries.length * 3) / 4) {
        int currentCapacity = entries.length;
        int newCapacity = currentCapacity * 2 + 1;
        Symbol[] newEntries = new Symbol[newCapacity];
        for (int i = currentCapacity - 1; i >= 0; --i) {
            Symbol currentEntry = entries[i];
            while (currentEntry != null) {
                int newCurrentEntryIndex = currentEntry.hashCode % newCapacity;
                Symbol nextEntry = currentEntry.next;
                currentEntry.next = newEntries[newCurrentEntryIndex];
                newEntries[newCurrentEntryIndex] = currentEntry;
                currentEntry = nextEntry;
            }
        }
        entries = newEntries;
    }
    entryCount++;
    int index = entry.hashCode % entries.length;
    entry.next = entries[index];
    return entries[index] = entry;
}

int addUninitializedType(final String value, final int bytecodeOffset) {
    final int UNINITIALIZED_TYPE_TAG = 129;

    int hashCode = 0x7FFFFFFF & (UNINITIALIZED_TYPE_TAG + value.hashCode() + bytecodeOffset);
    Symbol entry = entries[hashCode % entries.length];
    while (entry != null) {
        if (entry.tag == UNINITIALIZED_TYPE_TAG
                && entry.hashCode == hashCode
                && entry.data == bytecodeOffset
                && entry.value.equals(value)) {
            return entry.index;
        }
        entry = entry.next;
    }
    return addTypeInternal(
            new Symbol(typeCount, UNINITIALIZED_TYPE_TAG, null, null, value, bytecodeOffset, hashCode));
}

private boolean correctTypeName(Type type, String paramTypeName) {
    String typeName = type.getClassName();
    // array notation needs cleanup.
    StringBuilder braces = new StringBuilder();
    while (typeName.endsWith("[]")) {
        braces.append('[');
        typeName = typeName.substring(0, typeName.length() - 2);
    }
    if (braces.length() != 0) {
        String symbol = PRIMITIVES.get(typeName);
        if (symbol != null) {
            typeName = braces.append(symbol).toString();
        } else {
            typeName = braces.append('L').append(typeName).append(';').toString();
        }
    }
    return typeName.equals(paramTypeName);
}

public Supplier createSupplier(Constructor constructor) {
    try {
        Class<?> declaringClass = constructor.getDeclaringClass();
        MethodHandles.Lookup lookup = JDKUtils.trustedLookup(declaringClass);
        MethodHandle methodHandle = lookup.findConstructor(
                declaringClass,
                MethodType.methodType(void.class)
        );

        CallSite callSite = LambdaMetafactory.metafactory(
                lookup,
                "get",
                METHOD_TYPE_SUPPLIER,
                METHOD_TYPE_OBJECT,
                methodHandle,
                MethodType.methodType(declaringClass)
        );
        return (Supplier) callSite.getTarget().invokeExact();
    } catch (Throwable ignored) {
        // ignore
    }
    return super.createSupplier(constructor);
}

public Function<Object, Object> getObject(Method method) {
    if (method == null) {
        return null;
    }
    Class<?> declaringClass = method.getDeclaringClass();
    MethodHandles.Lookup lookup = JDKUtils.trustedLookup(declaringClass);
    try {
        MethodHandle handle = lookup.unreflect(method);
        return (Function<Object, Object>) LambdaMetafactory.metafactory(
                lookup,
                "apply",
                MethodType.methodType(Function.class),
                MethodType.methodType(Object.class, Object.class),
                handle,
                MethodType.methodType(method.getReturnType(), method.getDeclaringClass())
        ).getTarget().invokeExact();
    } catch (Throwable e) {
        throw new RuntimeException("Failed to create lambda for method: " + method, e);
    }
}

static Object parse(String text, JSONReader.Feature... features) {
    if (text == null || text.isEmpty()) {
        return null;
    }

    ObjectReaderProvider provider = JSONFactory.getDefaultObjectReaderProvider();
    final JSONReader.Context context = new JSONReader.Context(provider, features);
    final ObjectReader<?> objectReader = provider.getObjectReader(Object.class, false);

    try (JSONReader reader = JSONReader.of(text, context)) {
        context.config(features);
        Object object = objectReader.readObject(reader, null, null, 0);
        if (reader.ch != EOI && (context.features & IgnoreCheckClose.mask) == 0) {
            throw new JSONException(reader.info("input not end"));
        }
        return object;
    }
}

